1	/* =========================================
2	   INCIDENT DASHBOARD — IncidentDashboard.css
3	   Extends Management.css + Users.css patterns.
4	   ========================================= */
5	
6	/* --- Summary Stat Cards --- */
7	.inc-stats-grid {
8	  display: grid;
9	  grid-template-columns: repeat(4, 1fr);
10	  gap: 20px;
11	  margin-bottom: 24px;
12	}
13	
14	.inc-stat-card {
15	  background: #1e2539;
16	  border: 1px solid #2d364f;
17	  border-radius: 12px;
18	  padding: 22px 24px;
19	  position: relative;
20	  overflow: hidden;
21	  transition: transform 0.2s, border-color 0.2s;
22	}
23	
24	.inc-stat-card::before {
25	  content: '';
26	  position: absolute;
27	  top: 0;
28	  left: 0;
29	  width: 4px;
30	  height: 100%;
31	}
32	
33	.inc-stat-card:hover {
34	  transform: translateY(-2px);
35	  border-color: #334155;
36	}
37	
38	.inc-stat-blue::before  { background: #3b82f6; }
39	.inc-stat-red::before   { background: #f87171; }
40	.inc-stat-orange::before { background: #f59e0b; }
41	.inc-stat-green::before  { background: #34d399; }
42	
43	.inc-stat-blue  { border-left: 4px solid #3b82f6; }
44	.inc-stat-red   { border-left: 4px solid #f87171; }
45	.inc-stat-orange { border-left: 4px solid #f59e0b; }
46	.inc-stat-green  { border-left: 4px solid #34d399; }
47	
48	/* Override the ::before left bar since we're using border-left */
49	.inc-stat-card::before { display: none; }
50	
51	.inc-stat-value {
52	  font-size: 2.2rem;
53	  font-weight: 800;
54	  color: #f8fafc;
55	  line-height: 1;
56	  margin-bottom: 6px;
57	}
58	
59	.inc-stat-blue  .inc-stat-value { color: #60a5fa; }
60	.inc-stat-red   .inc-stat-value { color: #f87171; }
61	.inc-stat-orange .inc-stat-value { color: #f59e0b; }
62	.inc-stat-green  .inc-stat-value { color: #34d399; }
63	
64	.inc-stat-label {
65	  font-size: 0.78rem;
66	  text-transform: uppercase;
67	  letter-spacing: 0.08em;
68	  font-weight: 700;
69	  color: #64748b;
70	}
71	
72	/* --- Filter Bar --- */
73	.inc-filter-bar {
74	  display: flex;
75	  gap: 12px;
76	  align-items: center;
77	  margin-bottom: 16px;
78	  flex-wrap: wrap;
79	}
80	
81	.inc-search-input {
82	  flex: 1;
83	  min-width: 200px;
84	  padding: 9px 14px;
85	  background: #1e293b;
86	  border: 1px solid #334155;
87	  border-radius: 8px;
88	  color: #e2e8f0;
89	  font-size: 0.9rem;
90	  outline: none;
91	  transition: border-color 0.2s;
92	}
93	
94	.inc-search-input::placeholder {
95	  color: #475569;
96	}
97	
98	.inc-search-input:focus {
99	  border-color: #3b82f6;
100	}
101	
102	.inc-select {
103	  padding: 9px 12px;
104	  background: #1e293b;
105	  border: 1px solid #334155;
106	  border-radius: 8px;
107	  color: #e2e8f0;
108	  font-size: 0.85rem;
109	  outline: none;
110	  cursor: pointer;
111	  transition: border-color 0.2s;
112	}
113	
114	.inc-select:focus {
115	  border-color: #3b82f6;
116	}
117	
118	/* --- Incident Badges --- */
119	.inc-badge {
120	  display: inline-block;
121	  padding: 4px 10px;
122	  border-radius: 6px;
123	  font-size: 0.72rem;
124	  font-weight: 700;
125	  text-transform: uppercase;
126	  letter-spacing: 0.04em;
127	  white-space: nowrap;
128	}
129	
130	/* Severity */
131	.inc-severity-critical {
132	  background: rgba(248, 113, 113, 0.12);
133	  color: #f87171;
134	  border: 1px solid rgba(248, 113, 113, 0.25);
135	}
136	
137	.inc-severity-high {
138	  background: rgba(245, 158, 11, 0.12);
139	  color: #f59e0b;
140	  border: 1px solid rgba(245, 158, 11, 0.25);
141	}
142	
143	.inc-severity-medium {
144	  background: rgba(251, 191, 36, 0.12);
145	  color: #fbbf24;
146	  border: 1px solid rgba(251, 191, 36, 0.25);
147	}
148	
149	.inc-severity-low {
150	  background: rgba(59, 130, 246, 0.12);
151	  color: #60a5fa;
152	  border: 1px solid rgba(59, 130, 246, 0.25);
153	}
154	
155	/* AI Source */
156	.inc-source-fr {
157	  background: rgba(56, 189, 248, 0.12);
158	  color: #38bdf8;
159	  border: 1px solid rgba(56, 189, 248, 0.25);
160	}
161	
162	.inc-source-od {
163	  background: rgba(192, 132, 252, 0.12);
164	  color: #c084fc;
165	  border: 1px solid rgba(192, 132, 252, 0.25);
166	}
167	
168	/* Resolution Status */
169	.inc-status-active {
170	  background: rgba(248, 113, 113, 0.12);
171	  color: #f87171;
172	  border: 1px solid rgba(248, 113, 113, 0.25);
173	}
174	
175	.inc-status-investigating {
176	  background: rgba(245, 158, 11, 0.12);
177	  color: #f59e0b;
178	  border: 1px solid rgba(245, 158, 11, 0.25);
179	}
180	
181	.inc-status-escalated {
182	  background: rgba(251, 191, 36, 0.12);
183	  color: #fbbf24;
184	  border: 1px solid rgba(251, 191, 36, 0.25);
185	}
186	
187	.inc-status-cleared {
188	  background: rgba(52, 211, 153, 0.12);
189	  color: #34d399;
190	  border: 1px solid rgba(52, 211, 153, 0.25);
191	}
192	
193	/* --- Detail Modal (wider than default modal-content) --- */
194	.inc-detail-modal {
195	  background: #1e293b;
196	  border: 1px solid #334155;
197	  border-radius: 16px;
198	  padding: 30px;
199	  width: 90%;
200	  max-width: 620px;
201	  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.6);
202	  animation: scaleUp 0.25s cubic-bezier(0.34, 1.56, 0.64, 1);
203	}
204	
205	.inc-modal-header {
206	  display: flex;
207	  justify-content: space-between;
208	  align-items: flex-start;
209	  margin-bottom: 24px;
210	  padding-bottom: 16px;
211	  border-bottom: 1px solid #334155;
212	}
213	
214	.inc-modal-header h2 {
215	  font-size: 1.25rem;
216	  font-weight: 700;
217	  color: #f8fafc;
218	  margin: 0 0 4px 0;
219	}
220	
