223	  display: grid;
224	  grid-template-columns: 1fr 1fr;
225	  gap: 16px 24px;
226	  margin-bottom: 20px;
227	}
228	
229	.inc-detail-item {
230	  display: flex;
231	  flex-direction: column;
232	  gap: 4px;
233	}
234	
235	.inc-detail-label {
236	  font-size: 0.7rem;
237	  text-transform: uppercase;
238	  letter-spacing: 0.08em;
239	  font-weight: 700;
