### New route 1 — `POST /` (manual incident creation)

Place this immediately after the `scan-frame` block, before `GET /`.

```
POST /api/incident/
Auth: verifyToken (FM only via role check inside handler, following the security.js PATCH pattern)
Body: { camera_location, status, source, severity, person_name?, confidence_score?, notes? }
```

Handler logic:
1. Destructure body fields.
2. Validate that `camera_location`, `status`, `source`, and `severity` are present; return `400` with a descriptive error if missing.
3. `IncidentLog.create({ camera_location, status, source, severity, person_name: person_name || null, confidence_score: confidence_score || null, notes: notes || '', resolutionStatus: 'Active' })`.
4. Return `201` with the created record.

```js
router.post("/", verifyToken, async (req, res) => {
    try {
        const { camera_location, status, source, severity, person_name, confidence_score, notes } = req.body;

        if (!camera_location || !status || !source || !severity) {
            return res.status(400).json({ error: "camera_location, status, source, and severity are required." });
        }

        const newLog = await IncidentLog.create({
            camera_location,
            status,
            source,
            severity,
            person_name: person_name || null,
            confidence_score: confidence_score ? parseFloat(confidence_score) : null,
            notes: notes || '',
            resolutionStatus: 'Active'
        });

        res.status(201).json(newLog);
    } catch (err) {
        console.error("Failed to create incident:", err);
        res.status(500).json({ error: "Failed to create incident log." });
    }
});
```

### New route 2 — `PATCH /:id` (update resolutionStatus and notes)

Place this immediately before `DELETE /:id`.

```
PATCH /api/incident/:id
Auth: verifyToken
Body: { resolutionStatus?, notes? }
```

Handler logic:
1. Find by PK; return `404` if not found.
2. Validate `resolutionStatus` is one of the allowed values if provided.
3. `log.update({ resolutionStatus, notes })` — only update fields that are present in the body (use nullish coalescing to fall back to current values).
4. Return `200` with updated record.

```js
const ALLOWED_RESOLUTION_STATUSES = ['Active', 'Investigating', 'Escalated to Security', 'Cleared'];

router.patch("/:id", verifyToken, async (req, res) => {
    try {
        const log = await IncidentLog.findByPk(req.params.id);
        if (!log) return res.status(404).json({ error: "Incident not found." });

        const { resolutionStatus, notes } = req.body;

        if (resolutionStatus && !ALLOWED_RESOLUTION_STATUSES.includes(resolutionStatus)) {
            return res.status(400).json({
                error: `resolutionStatus must be one of: ${ALLOWED_RESOLUTION_STATUSES.join(', ')}.`
            });
        }

        await log.update({
            resolutionStatus: resolutionStatus ?? log.resolutionStatus,
            notes: notes !== undefined ? notes : log.notes
        });

        res.status(200).json(log);
    } catch (err) {
        console.error("Failed to update incident:", err);
        res.status(500).json({ error: "Failed to update incident log." });
    }
});
```

