### 3e. Seeding + Fetch logic (`useEffect` on mount)

```js
const fetchIncidents = useCallback(async () => {
    setLoading(true);
    setApiError('');
    try {
        const res = await axios.get('/api/incident', {
            headers: { Authorization: `Bearer ${getToken()}` }
        });
        setIncidents(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
        console.error('Failed to fetch incidents:', err);
        setApiError('Failed to load incidents. Displaying last known data.');
        showToast('Failed to load incidents from server.');
    } finally {
        setLoading(false);
    }
}, []);

useEffect(() => {
    const SEED_FLAG = 'flowguard_incidents_seeded';

    const seedAndFetch = async () => {
        if (!localStorage.getItem(SEED_FLAG)) {
            // First ever load — seed the 12 static incidents
            try {
                const token = getToken();
                for (const inc of STATIC_INCIDENTS) {
                    await axios.post('/api/incident', {
                        camera_location: inc.camera_location,
                        status: inc.status,
                        source: inc.source,
                        severity: inc.severity,
                        person_name: inc.person_name || undefined,
                        confidence_score: inc.confidence_score || undefined,
                        notes: inc.notes || ''
                    }, { headers: { Authorization: `Bearer ${token}` } });
                }
                localStorage.setItem(SEED_FLAG, 'true');
            } catch (err) {
                console.warn('Seeding failed (server may be empty or token expired):', err.message);
                // Still proceed to fetch whatever is in DB
            }
        }
        await fetchIncidents();
    };

    seedAndFetch();
}, [fetchIncidents]);
```

Note on seeding: the loop is sequential (`await` inside `for...of`) to avoid hammering the server with 12 concurrent POSTs. If seeding fails partway (e.g. token expired), `SEED_FLAG` is not set, so next load retries. If the server is already populated from a previous seed, duplicate rows will appear — this is acceptable for test data. The flag is a one-time guard that only clears if you clear localStorage.

