/* =========================================
   CRUD ADDITIONS
   ========================================= */

/* --- "+ Log Incident" header button --- */
.inc-create-btn {
  background: linear-gradient(135deg, #2563eb, #0891b2);
  color: white;
  border: 1px solid rgba(147, 197, 253, 0.35);
  padding: 10px 18px;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.88rem;
  cursor: pointer;
  white-space: nowrap;
  transition: transform 0.15s, box-shadow 0.15s;
  box-shadow: 0 6px 18px rgba(37, 99, 235, 0.2);
  align-self: center;
}

.inc-create-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 10px 24px rgba(37, 99, 235, 0.35);
}

/* --- Create modal (wider than detail modal) --- */
.inc-create-modal {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 16px;
  padding: 30px;
  width: 90%;
  max-width: 660px;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.6);
  animation: scaleUp 0.25s cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* --- Form grid inside create modal --- */
.inc-form {
  margin-top: 20px;
}

.inc-form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px 20px;
}

.inc-form-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.inc-form-full {
  grid-column: 1 / -1;
}

/* --- Textarea (create form + edit mode) --- */
.inc-notes-textarea {
  background: #0f172a;
  border: 1px solid #334155;
  border-radius: 8px;
  color: #e2e8f0;
  font-size: 0.88rem;
  line-height: 1.6;
  padding: 10px 14px;
  resize: vertical;
  outline: none;
  width: 100%;
  box-sizing: border-box;
  transition: border-color 0.2s;
  font-family: inherit;
}

.inc-notes-textarea:focus {
  border-color: #3b82f6;
}

.inc-notes-textarea::placeholder {
  color: #475569;
}

/* --- Primary save button --- */
.inc-save-btn {
  background: #2563eb;
  color: white;
  border: none;
  padding: 10px 22px;
  border-radius: 8px;
  font-weight: 700;
