1	const express = require('express');
2	const router = express.Router();
3	const { IncidentLog } = require('../models');
4	const { Op } = require("sequelize");
5	const axios = require('axios');
6	const multer = require('multer');
7	const FormData = require('form-data');
8	const { verifyToken } = require('../middlewares/auth');
9	require('dotenv').config();
10	
11	const ALLOWED_STATUSES = ['Active', 'Investigating', 'Escalated to Security', 'Cleared'];
12	
13	// Memory storage for incoming CCTV frames
14	const upload = multer({ storage: multer.memoryStorage() });
15	
16	// -------------------------------------------------------------
17	// AI INTEGRATION ROUTE: Scan frame and save to DB automatically
18	// -------------------------------------------------------------
19	router.post("/scan-frame", upload.single('file'), async (req, res) => {
20	    const cameraLocation = req.body.camera_location || "Unknown Sector";
21	
22	    if (!req.file) {
23	        return res.status(400).json({ error: "No image frame provided" });
24	    }
25	
26	    try {
27	        // 1. Package the frame for Python
28	        const formData = new FormData();
29	        formData.append('file', req.file.buffer, req.file.originalname);
30	
31	        // 2. Request AI analysis
32	        const aiResponse = await axios.post(process.env.PYTHON_AI_URL, formData, {
33	            headers: formData.getHeaders()
34	        });
35	
36	        const faces = aiResponse.data.faces;
37	        const savedLogs = [];
38	
39	        // 3. Save AI results into PostgreSQL via Sequelize
40	        for (let face of faces) {
41	            let newLog = await IncidentLog.create({
42	                camera_location: cameraLocation,
43	                status: face.status,
44	                person_name: face.name,
45	                confidence_score: face.confidence
46	            });
47	            savedLogs.push(newLog);
48	
49	            if (face.status === "UNAUTHORIZED_ACCESS") {
50	                console.log(`🚨 ALERT: Unauthorized access (${face.name}) at ${cameraLocation}!`);
51	            } else {
52	                console.log(`✅ LOGGED: ${face.name} authorized at ${cameraLocation}.`);
53	            }
54	        }
55	
56	        res.json({ success: true, ai_detections: faces, db_logs: savedLogs });
57	
58	    } catch (err) {
59	        console.error("AI Communication Error:", err.message);
60	        res.status(500).json({ error: "Failed to process frame with AI Service" });
61	    }
62	});
63	
64	// -------------------------------------------------------------
65	// Manual FM incident creation
66	// -------------------------------------------------------------
67	router.post("/", verifyToken, async (req, res) => {
68	    const { camera_location, status, source, severity, person_name, confidence_score, notes } = req.body;
69	    if (!camera_location || !status || !source || !severity) {
70	        return res.status(400).json({ error: "camera_location, status, source, and severity are required." });
71	    }
72	    try {
73	        const log = await IncidentLog.create({
74	            camera_location,
75	            status,
76	            source,
77	            severity,
78	            person_name: person_name || null,
79	            confidence_score: confidence_score ? parseFloat(confidence_score) : null,
80	            notes: notes || '',
81	            resolutionStatus: 'Active'
82	        });
83	        res.status(201).json(log);
84	    } catch (err) {
85	        console.error("Failed to create incident:", err);
86	        res.status(500).json({ error: "Failed to create incident log." });
87	    }
88	});
89	
90	// -------------------------------------------------------------
91	// STANDARD CRUD: Get all logs for React Dashboard
92	// -------------------------------------------------------------
93	router.get("/", async (req, res) => {
94	    let condition = {};
95	    let search = req.query.search;
96	    
97	    // Allow React frontend to search by name or location
98	    if (search) {
99	        condition[Op.or] = [
