/* =========================================
   INCIDENT DASHBOARD — IncidentDashboard.css
   Extends Management.css + Users.css patterns.
   ========================================= */

/* --- Summary Stat Cards --- */
.inc-stats-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
  margin-bottom: 24px;
}

.inc-stat-card {
  background: #1e2539;
  border: 1px solid #2d364f;
  border-radius: 12px;
  padding: 22px 24px;
  position: relative;
  overflow: hidden;
  transition: transform 0.2s, border-color 0.2s;
}

.inc-stat-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 4px;
  height: 100%;
}

.inc-stat-card:hover {
  transform: translateY(-2px);
  border-color: #334155;
}

.inc-stat-blue::before  { background: #3b82f6; }
.inc-stat-red::before   { background: #f87171; }
.inc-stat-orange::before { background: #f59e0b; }
.inc-stat-green::before  { background: #34d399; }

.inc-stat-blue  { border-left: 4px solid #3b82f6; }
.inc-stat-red   { border-left: 4px solid #f87171; }
.inc-stat-orange { border-left: 4px solid #f59e0b; }
.inc-stat-green  { border-left: 4px solid #34d399; }

/* Override the ::before left bar since we're using border-left */
.inc-stat-card::before { display: none; }

.inc-stat-value {
  font-size: 2.2rem;
  font-weight: 800;
  color: #f8fafc;
  line-height: 1;
  margin-bottom: 6px;
}

.inc-stat-blue  .inc-stat-value { color: #60a5fa; }
.inc-stat-red   .inc-stat-value { color: #f87171; }
.inc-stat-orange .inc-stat-value { color: #f59e0b; }
.inc-stat-green  .inc-stat-value { color: #34d399; }

.inc-stat-label {
  font-size: 0.78rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-weight: 700;
  color: #64748b;
}

/* --- Filter Bar --- */
.inc-filter-bar {
  display: flex;
  gap: 12px;
  align-items: center;
  margin-bottom: 16px;
  flex-wrap: wrap;
}

.inc-search-input {
  flex: 1;
  min-width: 200px;
  padding: 9px 14px;
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 8px;
  color: #e2e8f0;
  font-size: 0.9rem;
  outline: none;
  transition: border-color 0.2s;
}

.inc-search-input::placeholder {
  color: #475569;
}

.inc-search-input:focus {
  border-color: #3b82f6;
}

.inc-select {
  padding: 9px 12px;
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 8px;
  color: #e2e8f0;
  font-size: 0.85rem;
  outline: none;
  cursor: pointer;
  transition: border-color 0.2s;
}

.inc-select:focus {
  border-color: #3b82f6;
}

/* --- Incident Badges --- */
.inc-badge {
  display: inline-block;
  padding: 4px 10px;
  border-radius: 6px;
  font-size: 0.72rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  white-space: nowrap;
}

/* Severity */
.inc-severity-critical {
  background: rgba(248, 113, 113, 0.12);
  color: #f87171;
  border: 1px solid rgba(248, 113, 113, 0.25);
}

.inc-severity-high {
  background: rgba(245, 158, 11, 0.12);
  color: #f59e0b;
  border: 1px solid rgba(245, 158, 11, 0.25);
}

.inc-severity-medium {
  background: rgba(251, 191, 36, 0.12);
  color: #fbbf24;
  border: 1px solid rgba(251, 191, 36, 0.25);
}

.inc-severity-low {
  background: rgba(59, 130, 246, 0.12);
  color: #60a5fa;
  border: 1px solid rgba(59, 130, 246, 0.25);
}

/* AI Source */
.inc-source-fr {
  background: rgba(56, 189, 248, 0.12);
  color: #38bdf8;
  border: 1px solid rgba(56, 189, 248, 0.25);
}

.inc-source-od {
  background: rgba(192, 132, 252, 0.12);
  color: #c084fc;
  border: 1px solid rgba(192, 132, 252, 0.25);
}

/* Resolution Status */
.inc-status-active {
  background: rgba(248, 113, 113, 0.12);
  color: #f87171;
  border: 1px solid rgba(248, 113, 113, 0.25);
}

.inc-status-investigating {
  background: rgba(245, 158, 11, 0.12);
  color: #f59e0b;
  border: 1px solid rgba(245, 158, 11, 0.25);
}

.inc-status-escalated {
  background: rgba(251, 191, 36, 0.12);
  color: #fbbf24;
  border: 1px solid rgba(251, 191, 36, 0.25);
}

.inc-status-cleared {
  background: rgba(52, 211, 153, 0.12);
  color: #34d399;
  border: 1px solid rgba(52, 211, 153, 0.25);
}

/* --- Detail Modal (wider than default modal-content) --- */
.inc-detail-modal {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 16px;
  padding: 30px;
  width: 90%;
  max-width: 620px;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.6);
  animation: scaleUp 0.25s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.inc-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #334155;
}

.inc-modal-header h2 {
  font-size: 1.25rem;
  font-weight: 700;
  color: #f8fafc;
  margin: 0 0 4px 0;
}

/* --- Two-column detail grid --- */
.inc-detail-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px 24px;
  margin-bottom: 20px;
}

.inc-detail-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.inc-detail-label {
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-weight: 700;
  color: #64748b;
}

.inc-detail-value {
  font-size: 0.92rem;
  color: #e2e8f0;
  font-weight: 500;
}

/* --- Notes section --- */
.inc-notes-section {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding-top: 16px;
  border-top: 1px solid #1e293b;
}

.inc-notes-box {
  background: #0f172a;
  border: 1px solid #334155;
  border-radius: 8px;
  padding: 12px 16px;
  color: #94a3b8;
  font-size: 0.88rem;
  line-height: 1.6;
  min-height: 56px;
}

/* --- Person cell — reuse user-info pattern inline --- */
.inc-person-cell {
  display: flex;
  align-items: center;
  gap: 10px;
}

.inc-person-initial {
  width: 28px;
  height: 28px;
  background: linear-gradient(135deg, #3b82f6, #0891b2);
  color: white;
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  font-weight: 700;
  font-size: 0.78rem;
  flex-shrink: 0;
}

/* =========================================
   RESPONSIVE
   ========================================= */
@media (max-width: 1024px) {
  .inc-stats-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .inc-stats-grid {
    grid-template-columns: 1fr 1fr;
    gap: 12px;
  }

  .inc-filter-bar {
    flex-direction: column;
    align-items: stretch;
  }

  .inc-search-input,
  .inc-select {
    width: 100%;
  }

  .inc-detail-grid {
    grid-template-columns: 1fr;
  }

  .inc-detail-modal {
    padding: 20px;
    width: 95%;
  }
}

@media (max-width: 480px) {
  .inc-stats-grid {
    grid-template-columns: 1fr;
  }
}

/* =========================================
   CRUD ADDITIONS
   ========================================= */

/* --- "+ Log Incident" header button --- */
.inc-create-btn {
  background: linear-gradient(135deg, #2563eb, #0891b2);
  color: white;
  border: 1px solid rgba(147, 197, 253, 0.35);
  padding: 10px 18px;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.88rem;
  cursor: pointer;
  white-space: nowrap;
  transition: transform 0.15s, box-shadow 0.15s;
  box-shadow: 0 6px 18px rgba(37, 99, 235, 0.2);
  align-self: center;
}

.inc-create-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 10px 24px rgba(37, 99, 235, 0.35);
}

/* --- Create modal (wider than detail modal) --- */
.inc-create-modal {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 16px;
  padding: 30px;
  width: 90%;
  max-width: 660px;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.6);
  animation: scaleUp 0.25s cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* --- Form grid inside create modal --- */
.inc-form {
  margin-top: 20px;
}

.inc-form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px 20px;
}

.inc-form-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.inc-form-full {
  grid-column: 1 / -1;
}

/* --- Textarea (create form + edit mode) --- */
.inc-notes-textarea {
  background: #0f172a;
  border: 1px solid #334155;
  border-radius: 8px;
  color: #e2e8f0;
  font-size: 0.88rem;
  line-height: 1.6;
  padding: 10px 14px;
  resize: vertical;
  outline: none;
  width: 100%;
  box-sizing: border-box;
  transition: border-color 0.2s;
  font-family: inherit;
}

.inc-notes-textarea:focus {
  border-color: #3b82f6;
}

.inc-notes-textarea::placeholder {
  color: #475569;
}

/* --- Primary save button --- */
.inc-save-btn {
  background: #2563eb;
  color: white;
  border: none;
  padding: 10px 22px;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.88rem;
  cursor: pointer;
  transition: background 0.2s, transform 0.15s;
}

.inc-save-btn:hover:not(:disabled) {
  background: #1d4ed8;
  transform: translateY(-1px);
}

.inc-save-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

/* --- Loading indicator --- */
.inc-loading-bar {
  color: #64748b;
  font-size: 0.85rem;
  padding: 4px 0 14px 0;
  letter-spacing: 0.03em;
}

/* --- Responsive: single column on small screens --- */
@media (max-width: 600px) {
  .inc-form-grid {
    grid-template-columns: 1fr;
  }

  .inc-create-modal {
    padding: 20px;
    width: 95%;
  }
}

