/* =========================================
   1. CORE LAYOUT & VARIABLES
   ========================================= */
.dashboard-layout {
  display: flex;
  height: 100vh;
  background-color: #0b0f1a; 
  color: #f8fafc;
  overflow: hidden;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Common Gradients & Colors */
.gradient-text {
  background: linear-gradient(to right, #60a5fa, #34d399);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-blue { color: #60a5fa; }
.text-green { color: #34d399; }
.text-red { color: #f87171; }

/* Status Dots */
.dot-online { background-color: #34d399; box-shadow: 0 0 8px #34d399; display: inline-block; width: 8px; height: 8px; border-radius: 50%; }
.dot-offline { background-color: #4b5563; display: inline-block; width: 8px; height: 8px; border-radius: 50%; }
.dot-warning { background-color: #f59e0b; box-shadow: 0 0 8px #f59e0b; display: inline-block; width: 8px; height: 8px; border-radius: 50%; }

/* =========================================
   2. SIDEBAR COMPONENTS
   ========================================= */
.sidebar {
  width: 240px;
  min-width: 240px; 
  background-color: #161b2c;
  border-right: 1px solid #232a3d;
  display: flex;
  flex-direction: column;
  position: sticky;
  top: 0;
  height: 100vh;
  z-index: 100;
  transition: left 0.3s ease; /* Smooth transition for mobile */
}

/* --- LOGO AREA FIX --- */
.sidebar-logo {
  padding: 30px 20px;
  display: flex;
  justify-content: space-between; /* Space between logo group and close btn */
  align-items: center;
  border-bottom: 1px solid #232a3d;
  width: 100%;
  box-sizing: border-box;
}

.logo-title {
  display: flex;
  align-items: center;
  gap: 12px;
}

.logo-title h2 {
  font-size: 22px !important;
  margin: 0 !important;
  line-height: 1 !important;
  font-weight: 700;
}

/* Close button hidden by default on desktop */
.close-sidebar-btn {
  display: none; 
}

/* --- NAVIGATION --- */
.sidebar-nav {
  flex: 1;
  padding: 20px 0;
  overflow-y: auto; /* Allow scrolling if many links */
}

.sidebar-nav a {
  display: block;
  padding: 12px 20px;
  color: #707a91;
  text-decoration: none;
  font-size: 0.9rem;
  transition: 0.2s;
  border-left: 4px solid transparent;
}

.sidebar-nav a.active, /* Use .active for React Router NavLink default */
.sidebar-nav a:hover {
  background: #1e2539;
  color: #60a5fa !important;
  border-left: 4px solid #3b82f6;
}

/* --- USER PROFILE (BOTTOM) --- */
.sidebar-bottom {
  padding: 20px;
  border-top: 1px solid #232a3d;
}

.user-profile {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 15px;
}

.user-avatar {
  font-size: 1.5rem;
  background: #0b0f1a;
  padding: 8px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.user-meta {
  display: flex !important;
  flex-direction: column !important;
  align-items: flex-start !important;
  justify-content: center;
  gap: 2px;
}

.user-name {
  font-weight: 600;
  font-size: 0.9rem;
  color: #f8fafc;
}

.user-role-tag {
  font-size: 0.75rem;
  color: #707a91;
}

.logout-btn {
  display: block;
  width: 100%;
  padding: 10px;
  background: rgba(239, 68, 68, 0.1);
  color: #ef4444;
  border: 1px solid rgba(239, 68, 68, 0.2);
  border-radius: 8px;
  text-align: center;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
}

.logout-btn:hover {
  background: #ef4444;
  color: white;
}

/* =========================================
   3. MAIN CONTENT DASHBOARD
   ========================================= */
.dashboard-main {
  flex: 1;
  padding: 30px;
  overflow-y: auto;
  overflow-x: hidden;
}

.dashboard-header {
  display: flex;
  justify-content: space-between;
  align-items: center; 
  margin-bottom: 30px;
}

.header-titles h1 { 
  font-size: 1.8rem; 
  margin: 0; 
}

.header-titles p { 
  color: #707a91; 
  font-size: 0.85rem; 
  margin: 5px 0 0 0; 
}

.header-time { 
  text-align: right; 
}

.time-text { 
  font-weight: 600; 
  margin: 0 0 5px 0; 
  color: #e2e8f0; 
  font-size: 0.95rem;
}

.timezone-text { 
  font-size: 0.8rem; 
