@media (max-width: 1024px) {
  .top-summary-row { grid-template-columns: repeat(2, 1fr); }
  .activity-cards-grid { grid-template-columns: repeat(2, 1fr); }
  .charts-section { grid-template-columns: 1fr; }
}

@media (max-width: 768px) {
  /* Hamburger Button */
  .mobile-menu-btn {
    display: flex !important;
    position: fixed;
    top: 15px;
    left: 15px;
    z-index: 1000;
    width: 45px;
    height: 45px;
    background: rgba(30, 41, 59, 0.8);
    color: white;
    border: 1px solid #334155;
    border-radius: 8px;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    cursor: pointer;
    backdrop-filter: blur(5px);
  }

  /* Sidebar Canvas Behavior */
  .sidebar {
    position: fixed;
    left: -100%;
    z-index: 999;
  }

  .sidebar.open {
    left: 0;
  }

  /* Activate Close Button inside Sidebar */
  .close-sidebar-btn {
    display: flex; 
    background: transparent;
    color: #94a3b8;
    border: none;
    font-size: 1.5rem;
    cursor: pointer;
    padding: 5px;
    align-items: center;
    justify-content: center;
    transition: color 0.3s ease;
  }

  .close-sidebar-btn:hover,
  .close-sidebar-btn:active {
    color: #f8fafc;
  }

  /* Overlay Background */
  .sidebar-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: rgba(0, 0, 0, 0.6);
    backdrop-filter: blur(2px);
    z-index: 998; 
  }

  /* Main Content Adjustments */
  .dashboard-main {
    padding: 90px 20px 20px;
  }

  .dashboard-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 15px;
  }

  .header-time {
    text-align: left;
  }

  .top-summary-row, 
  .activity-cards-grid {
    grid-template-columns: 1fr;
  }
}

