}

.inc-notes-textarea::placeholder {
  color: #475569;
}

/* --- Primary save button --- */
.inc-save-btn {
  background: #2563eb;
  color: white;
  border: none;
  padding: 10px 22px;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.88rem;
  cursor: pointer;
  transition: background 0.2s, transform 0.15s;
}

.inc-save-btn:hover:not(:disabled) {
  background: #1d4ed8;
  transform: translateY(-1px);
}

.inc-save-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

/* --- Loading indicator --- */
.inc-loading-bar {
  color: #64748b;
  font-size: 0.85rem;
  padding: 4px 0 14px 0;
  letter-spacing: 0.03em;
